SELECT session_description
FROM sensory_sessions
WHERE session_id = 1;

SELECT AVG(acc_x) AS average_acceleration_x
FROM sensory_data
WHERE session_id = 1;

SELECT MAX(timestamp) AS latest_time
FROM sensory_data
WHERE session_id = 0;

SELECT data_quality
FROM sensory_data
WHERE session_id = 0;

SELECT MAX(acc_x) AS max_acceleration_x
FROM sensory_data
WHERE device_id = 0 AND session_id = 0;

SELECT AVG(acc_x) AS avg_acceleration_x
FROM sensory_data
WHERE session_id = 1 AND device_id = 0;

SELECT COUNT(session_id) AS session_count
FROM sensory_sessions
WHERE device_id = 0;

SELECT session_id, session_description
FROM sensory_sessions
WHERE data_format = 'CSV';

SELECT timestamp, acc_x, gyr_y, data_quality
FROM sensory_data
WHERE data_quality = 'medium' AND timestamp > 1.0;

SELECT DISTINCT a.session_id 
FROM anomalies a
ORDER BY a.timestamp, a.session_id;
